<code>
content = "using System;
using System.Text;

public class Program
{
    public static string RemoveSequentialDuplicates(string str)
    {
        if (string.IsNullOrEmpty(str)) return str;

        StringBuilder sb = new StringBuilder();
        char lastChar = str[0];
        sb.Append(lastChar);

        for (int i = 1; i < str.Length; i++)
        {
            if (str[i] != lastChar)
            {
                sb.Append(str[i]);
                lastChar = str[i];
            }
        }

        return sb.ToString();
    }

    public static void Main()
    {
        string str = "azxxzy";
        string result = RemoveSequentialDuplicates(str);
        Console.WriteLine($"Input: {str} -> Output: {result}");
    }
}"
