<code>
code = """public class Main {
    public static void main(String[] args) {
        try {
            System.out.println("Test 1 (Hello, World!): " + uppercaseConversion("Hello, World!"));
            System.out.println("Test 2 (empty): " + uppercaseConversion(""));
        } catch (Exception e) {
            System.out.println("Error: " + e.getMessage()); 
        }
        try {
            System.out.println("Test 3 (null): " + uppercaseConversion(null));
        } catch (Exception e) {
            System.out.println("Error: " + e.getMessage()); 
        }
    }

    public static String uppercaseConversion(String input) throws Exception {
        if (input == null) {
            throw new Exception("String input is null.");
        } else if (input.isEmpty()) {
            throw new Exception("String input is empty.");
        } else {
            StringBuilder output = new StringBuilder();
            for (char c : input.toCharArray()) {
                if (c >= 'a' && c <= 'z') {
                    output.append((char)(c - 'a' + 'A'));
                } else {
                    output.append(c);
                }
            }
            return output.toString();
        }
    }
}"""
