def lucas_sequence(n):
    if n <= 0:
        return []
    if n == 1:
        return [2]
    lucas_seq = [2, 1]
    for i in range(2, n):
        lucas_seq.append(lucas_seq[-1] + lucas_seq[-2])
    return lucas_seq

def harmonic_mean(sequence):
    if not sequence:
        return 0
    if 0 in sequence:
        return 0
    return len(sequence) / sum(1.0 / num for num in sequence)

