function checkAccount($user)
{
    try {
       Get-CimInstance Win32_UserAccount -ErrorAction Stop | Where-Object -Property Name -Contains $user | Select-Object -ExpandProperty Name -ErrorAction Stop
    }
    catch {
        Write-Warning -Message 'Oops, ran into an issue'
