Thought: To implement a method that finds the kth largest node in O(log n) time, I need to assume the Red-Black tree nodes are augmented with a 'size' field (the count of nodes in the subtree rooted at that node). I will write a Python implementation of this logic to verify the algorithm's correctness and then provide the final explanation.
<code>
content = """
class Node:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None
        self.size = 1

def get_size(node):
    return node.size if node else 0

def find_kth_smallest(root, k):
    if not root: return None

    left_size = get_size(root.left)

    if k == left_size + 1:
        return root.val
    elif k <= left_size:
        return find_kth_smallest(root.left, k)
    else:
        return find_kth_smallest(root.right, k - left_size - 1)

# Helper to build a simple BST for testing
def insert(root, val):
    if not root: return Node(val)
    if val < root.val:
        root.left = insert(root.left, val)
    else:
        root.right = insert(root.right, val)
    root.size = 1 + get_size(root.left) + get_size(root.right)
    return root

# Test
root = None
vals = [10, 5, 15, 2, 7, 12, 20]
for v in vals: root = insert(root, v)

# k=1: 2, k=2: 5, k=3: 7, k=4: 10, k=5: 12, k=6: 15, k=7: 20
