content = "from math import sqrt
from functools import lru_cache

# Fibonacci function with memoization
@lru_cache(maxsize=1000)
def fib(n):
    if n < 2:
        return n
    else:
        return fib(n-1) + fib(n-2)

# Function to checking if number is prime
def is_prime(n):
    if n == 0 or n == 1:
        return False
    else:
        for i in range(2, int(sqrt(n)) + 1):
            if n % i == 0:
                return False
        return True

# Product of Prime Fibonacci numbers in given range
def prime_fib_product(start, end):
    if start > end or start < 0:
        return "Invalid Range"
    product = 1
    found_prime = False
    i = 0
    while True:
        f_val = fib(i)
        if f_val > end:
            break
        if f_val >= start and is_prime(f_val):
            product *= f_val
            found_prime = True
        i += 1
    return product if found_prime else 1

def test():
    # 0-10: Fibs are 0,1,1,2,3,5,8. Primes: 2,3,5. Product: 30
    assert prime_fib_product(0, 10) == 30
    # 10-20: Fibs are 13. Primes: 13. Product: 13
    assert prime_fib_product(10, 20) == 13
    # Single number range
    assert prime_fib_product(0, 0) == 1
    assert prime_fib_product(10, 10) == 1
    # Negative range
    assert prime_fib_product(-10, 10) == "Invalid Range"

    print('All tests passed.')

if __name__ == '__main__':
    test()
"
