content = "import random
import string

def is_prime(n) -> bool:
    if n < 2:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

def next_composite(n) -> int:
    if n < 4:
        return 4
    n += 1
    while is_prime(n):
        n += 1
    return n

def flip_case_replace_prime_shuffle(s: str) -> str:
    new_string = ''
    for char in s:
        # Check if character is digit and if it's a prime number
        if char.isdigit() and is_prime(int(char)):
            new_string += str(next_composite(int(char)))
        # Check if character is an alphabet and flip case
        elif char.isalpha():
            new_string += char.upper() if char.islower() else char.lower()
        # Check if character is a special character (punctuation) and duplicate it
        elif char in string.punctuation:
            new_string += char + char
        else:
            new_string += char

    # Randomize the arrangement of all characters
    char_list = list(new_string)
    random.shuffle(char_list)
    return ''.join(char_list)

if __name__ == '__main__':
    test_val = 'Hello5!'
    print(f'Input: {test_val}')
    print(f'Result: {flip_case_replace_prime_shuffle(test_val)}')
"
