import math

def sanitize_value(val):
    if val is None: return float('inf')
    try:
        return float(val)
    except (TypeError, ValueError):
        return float('inf')

def min_heapify(arr, n, i):
    smallest = i
    left = 2 * i + 1
    right = 2 * i + 2
    swaps = 0

    v_i = sanitize_value(arr[i])

    if left < n:
        v_left = sanitize_value(arr[left])
        if v_left < v_i:
            smallest = left

    if right < n:
        v_right = sanitize_value(arr[right])
        v_smallest = sanitize_value(arr[smallest])
        if v_right < v_smallest:
            smallest = right

    if smallest != i:
        arr[i], arr[smallest] = arr[smallest], arr[i]
        swaps = 1 + min_heapify(arr, n, smallest)
    return swaps

def convert_min_heap(arr):
    n = len(arr)
    swaps = 0
    for i in range(n // 2 - 1, -1, -1):
        swaps += min_heapify(arr, n, i)
    return arr, swaps

def max_heapify(arr, n, i):
    largest = i
    left = 2 * i + 1
    right = 2 * i + 2
    swaps = 0

    v_i = sanitize_value(arr[i])

    if left < n:
