        if v_left > v_i:
            largest = left

    if right < n:
        v_right = sanitize_value(arr[right])
        v_largest = sanitize_value(arr[largest])
        if v_right > v_largest:
            largest = right

    if largest != i:
        arr[i], arr[largest] = arr[largest], arr[i]
        swaps = 1 + max_heapify(arr, n, largest)
    return swaps

def convert_max_heap(arr):
    n = len(arr)
    swaps = 0
