def how_many_times(string: str, substring: str) -> int:
    """Calculate the frequency of a given substring in a source string, including overlapping instances."""
    count = start = 0
    while True:
        start = string.find(substring, start) + 1
        if start > 0:
            count += 1
        else:
            return count


def count_subsequences(string: str, substring: str) -> int:
    """Use dynamic programming to find the occurrences of a specific substring 
    appearing as a non-overlapping subsequence within the source string."""
    m, n = len(substring), len(string)
    lookup = [[0] * (n + 1) for _ in range(m + 1)]

    # if the first string is empty
    for i in range(n + 1):
        lookup[0][i] = 1

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if substring[i - 1] == string[j - 1]:
                lookup[i][j] = lookup[i - 1][j - 1] + lookup[i][j - 1]
            else:
                lookup[i][j] = lookup[i][j - 1]

    return lookup[m][n]
