code = "import java.util.*;
import javafx.util.Pair;

public class Solution {
    /**
    * Returns encoded string by shifting every character by a random integer between 1 and 5.
    * @param s string to encode
    * @return Pair object that includes the encoded string and the shifts used
    */
    public Pair<String, int[]> encodeShift(String s) {
        StringBuilder sb = new StringBuilder();
        int[] shifts = new int[s.length()];
        Random rand = new Random();

        for (int i = 0; i < s.length(); i++) {
            int shift = rand.nextInt(5) + 1;
            shifts[i] = shift;
            char c = (char) (s.charAt(i) + shift);
            sb.append(c);
        }

        return new Pair<>(sb.toString(), shifts);
    }

    /**
    * Takes as input a string encoded with encodeShift function, and the array of shifts used.
    * Returns the decoded string.
    * @param s encoded string to decode
    * @param shifts array of shift used in encoding
    * @return decoded string
    */
    public String decodeShift(String s, int[] shifts) {
        if (s == null || shifts == null || s.length() != shifts.length) {
            throw new IllegalArgumentException("Invalid input: string and shifts array must be non-null and of same length");
        }
        StringBuilder sb = new StringBuilder();

        for (int i = 0; i < s.length(); i++) {
            char c = (char) (s.charAt(i) - shifts[i]);
            sb.append(c);
        }

        return sb.toString();
    }

    public static void main(String[] args) {
        Solution solution = new Solution();
        String original = "Hello World!";
        Pair<String, int[]> encoded = solution.encodeShift(original);
        System.out.println("Encoded: " + encoded.getKey());
        String decoded = solution.decodeShift(encoded.getKey(), encoded.getValue());
        System.out.println("Decoded: " + decoded);
        System.out.println("Success: " + original.equals(decoded));
    }
}"
