      const parsed = await parseString.parseStringPromise(response.data);
      results.push({
        source: url,
        items: parsed.rss.channel.item
      });
    } catch (e) {
      console.error(`Error fetching ${url}: ${e.message}`);
    }
  }
  return results;
};
